import json, asyncio
import anthropic

client = anthropic.AsyncAnthropic()

async def stream_and_parse_tool_calls(
    messages: list[dict],
    tools: list[dict],
) -> tuple[list[dict], list[dict]]:
    """
    Returns (content_blocks, tool_calls) where tool_calls are fully assembled.
    Yields nothing — call this when you need the complete tool inputs before dispatching.
    """
    text_blocks: list[dict] = []
    tool_calls: list[dict] = []
    block_buffers: dict[int, str] = {}   # index -> accumulated JSON
    block_meta: dict[int, dict] = {}     # index -> {id, name}

    async with client.messages.stream(
        model="claude-sonnet-5",
        max_tokens=4096,
        messages=messages,
        tools=tools,
    ) as stream:
        async for event in stream:
            if event.type == "content_block_start":
                blk = event.content_block
                if blk.type == "text":
                    block_buffers[event.index] = ""
                elif blk.type == "tool_use":
                    block_meta[event.index] = {"id": blk.id, "name": blk.name}
                    block_buffers[event.index] = ""

            elif event.type == "content_block_delta":
                delta = event.delta
                if delta.type == "text_delta":
                    block_buffers[event.index] = block_buffers.get(event.index, "") + delta.text
                elif delta.type == "input_json_delta":
                    block_buffers[event.index] = block_buffers.get(event.index, "") + delta.partial_json

            elif event.type == "content_block_stop":
                idx = event.index
                if idx in block_meta:
                    meta = block_meta.pop(idx)
                    raw_json = block_buffers.pop(idx, "{}")
                    tool_calls.append({
                        "type": "tool_use",
                        "id": meta["id"],
                        "name": meta["name"],
                        "input": json.loads(raw_json),
                    })
                elif idx in block_buffers:
                    text_blocks.append({
                        "type": "text",
                        "text": block_buffers.pop(idx),
                    })

    return text_blocks, tool_calls

import json, asyncio
import anthropic
from fastapi import FastAPI, Request
from fastapi.responses import StreamingResponse

app = FastAPI()
client = anthropic.AsyncAnthropic()

async def full_agent_stream(request: Request, messages: list[dict], tools: list[dict]):
    """
    Async generator that yields SSE events for:
    - text tokens while Claude is writing
    - tool_start when a tool call begins
    - tool_executing while the tool runs
    - tool_result when the tool finishes
    - done when the loop completes
    """
    while True:
        text_blocks: list[dict] = []
        tool_calls: list[dict] = []
        block_buffers: dict[int, str] = {}
        block_meta: dict[int, dict] = {}

        async with client.messages.stream(
            model="claude-sonnet-5",
            max_tokens=4096,
            messages=messages,
            tools=tools,
        ) as stream:
            async for event in stream:
                if await request.is_disconnected():
                    return

                if event.type == "content_block_start" and event.content_block.type == "tool_use":
                    blk = event.content_block
                    block_meta[event.index] = {"id": blk.id, "name": blk.name}
                    block_buffers[event.index] = ""
                    # Immediately tell the UI a tool call is starting
                    yield f"data: {json.dumps({'type': 'tool_start', 'name': blk.name, 'id': blk.id})}\n\n"

                elif event.type == "content_block_start" and event.content_block.type == "text":
                    block_buffers[event.index] = ""

                elif event.type == "content_block_delta":
                    delta = event.delta
                    if delta.type == "text_delta":
                        block_buffers[event.index] = block_buffers.get(event.index, "") + delta.text
                        yield f"data: {json.dumps({'type': 'token', 'text': delta.text})}\n\n"
                    elif delta.type == "input_json_delta":
                        block_buffers[event.index] = block_buffers.get(event.index, "") + delta.partial_json

                elif event.type == "content_block_stop":
                    idx = event.index
                    if idx in block_meta:
                        meta = block_meta.pop(idx)
                        raw = block_buffers.pop(idx, "{}")
                        call = {"type": "tool_use", "id": meta["id"], "name": meta["name"], "input": json.loads(raw)}
                        tool_calls.append(call)
                    elif idx in block_buffers:
                        text_blocks.append({"type": "text", "text": block_buffers.pop(idx)})

            final = await stream.get_final_message()

        if final.stop_reason != "tool_use" or not tool_calls:
            yield f"data: {json.dumps({'type': 'done'})}\n\n"
            return

        # Append assistant turn
        messages.append({"role": "assistant", "content": final.content})

        # Execute tools and stream results
        for tc in tool_calls:
            yield f"data: {json.dumps({'type': 'tool_executing', 'name': tc['name'], 'id': tc['id']})}\n\n"
            try:
                result = await dispatch_tool(tc["name"], tc["input"])
                yield f"data: {json.dumps({'type': 'tool_result', 'id': tc['id'], 'result': str(result)[:500]})}\n\n"
            except Exception as e:
                yield f"data: {json.dumps({'type': 'tool_error', 'id': tc['id'], 'error': str(e)})}\n\n"
                result = f"Error: {e}"

            messages.append({
                "role": "user",
                "content": [{"type": "tool_result", "tool_use_id": tc["id"], "content": str(result)}],
            })

@app.post("/agent/stream")
async def agent_stream(request: Request, body: dict):
    return StreamingResponse(
        full_agent_stream(request, body["messages"], body["tools"]),
        media_type="text/event-stream",
        headers={"Cache-Control": "no-cache", "X-Accel-Buffering": "no"},
    )

async function streamAgent(messages, tools) {
  const resp = await fetch("/agent/stream", {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ messages, tools }),
  });

  const reader = resp.body.getReader();
  const decoder = new TextDecoder();
  let buf = "";
  const toolElements = {}; // id -> DOM element

  while (true) {
    const { done, value } = await reader.read();
    if (done) break;

    buf += decoder.decode(value, { stream: true });
    const chunks = buf.split("\n\n");
    buf = chunks.pop();

    for (const chunk of chunks) {
      if (!chunk.startsWith("data: ")) continue;
      const event = JSON.parse(chunk.slice(6));

      switch (event.type) {
        case "token":
          appendTextToken(event.text);
          break;

        case "tool_start":
          // Show a "calling tool..." pill in the UI
          toolElements[event.id] = renderToolCallPill(event.name, "pending");
          break;

        case "tool_executing":
          toolElements[event.id]?.setStatus("executing");
          break;

        case "tool_result":
          toolElements[event.id]?.setStatus("done");
          toolElements[event.id]?.showResult(event.result);
          break;

        case "tool_error":
          toolElements[event.id]?.setStatus("error");
          toolElements[event.id]?.showError(event.error);
          break;

        case "done":
          markResponseComplete();
          break;
      }
    }
  }
}

