import asyncio

async def execute_parallel_tool_calls(
    tool_calls: list[dict],
) -> list[dict]:
    """Execute all tool calls from one assistant turn concurrently."""
    async def run_one(tc: dict) -> dict:
        try:
            result = await dispatch_tool(tc["name"], tc["input"])
            return {"type": "tool_result", "tool_use_id": tc["id"], "content": str(result)}
        except Exception as e:
            return {
                "type": "tool_result",
                "tool_use_id": tc["id"],
                "content": f"Error: {e}",
                "is_error": True,
            }

    results = await asyncio.gather(*[run_one(tc) for tc in tool_calls])
    return list(results)

